	}
	content := "---\nddx:\n  id: " + id + "\n  depends_on:\n    - " + artifactID +
		"\n  execution:\n    kind: command\n    required: " + reqStr + "\n    command:\n" + cmdLines + "---\n# " + id + "\n"
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
		t.Fatal(err)
	}
